<?php namespace App\Console\Commands; use Illuminate\Console\Command; use Illuminate\Support\Facades\DB; use Carbon\Carbon; class DatabaseCleanup extends Command { protected $signature = 'database:cleanup {--force : التنفيذ المباشر دون تأكيد}'; protected $description = 'تنظيف السجلات القديمة من قاعدة البيانات التي تجاوزت 90 يوماً'; public function handle() { $days = 90; $thresholdDate = Carbon::now()->subDays($days); if (!$this->option('force') && !$this->confirm("هل أنت متأكد من رغبتك في حذف السجلات الأقدم من {$days} يوماً؟")) { $this->info('تم إلغاء العملية.'); return Command::SUCCESS; } $this->info('جاري بدء عملية التنظيف...'); $deletedCount = DB::table('audit_logs') ->where('created_at', '<', $thresholdDate) ->delete(); $this->info("تم حذف {$deletedCount} سجل من سجلات التدقيق."); $this->info('عملية التنظيف تمت بنجاح.'); return Command::SUCCESS; } }